// poliub-frontend/src/context/AuthContext.js
import React, { createContext, useState, useEffect, useContext } from "react";
import axios from "axios";

const AuthContext = createContext(null);

/**
 * AuthProvider wrapa toda a aplicação e mantém:
 * - token JWT em localStorage e em axios.defaults.headers
 * - objeto user (id, role, nome, ra, periodo_id, usuario)
 */
export function AuthProvider({ children }) {
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);

  // Ao montar, tenta recuperar token e user do localStorage
  useEffect(() => {
    const tokenEmStorage = localStorage.getItem("token");
    const userEmStorage = localStorage.getItem("user");
    if (tokenEmStorage && userEmStorage) {
      setToken(tokenEmStorage);
      setUser(JSON.parse(userEmStorage));
      axios.defaults.headers.common[
        "Authorization"
      ] = `Bearer ${tokenEmStorage}`;
    }
  }, []);

  /**
   * Faz login (POST /api/login). Se der certo, armazena:
   * - token (state + localStorage + axios.defaults.headers)
   * - user (state + localStorage)
   */
  const login = async (usuario, senha) => {
    try {
      const response = await axios.post("/api/login", {
        usuario,
        senha,
      });
      const {
        token: novoToken,
        id,
        role,
        nome,
        ra,
        periodo_id,
        usuario: usuarioRetornado,
      } = response.data;

      setToken(novoToken);
      setUser({ id, role, nome, ra, periodo_id, usuario: usuarioRetornado });

      localStorage.setItem("token", novoToken);
      localStorage.setItem(
        "user",
        JSON.stringify({ id, role, nome, ra, periodo_id, usuario: usuarioRetornado })
      );

      axios.defaults.headers.common[
        "Authorization"
      ] = `Bearer ${novoToken}`;

      return { success: true };
    } catch (err) {
      console.error("Erro no login:", err);
      return { success: false, message: err.response?.data?.error || err };
    }
  };

  /**
   * Faz logout: limpa token + user de state, localStorage e axios.defaults
   */
  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    delete axios.defaults.headers.common["Authorization"];
  };

  return (
    <AuthContext.Provider value={{ token, user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

/**
 * Custom hook para usar AuthContext em qualquer componente:
 * const { token, user, login, logout } = useAuth();
 */
export function useAuth() {
  return useContext(AuthContext);
}
